CREATE TABLE `fact_sales` (
  `saleid` int NOT NULL,
  `productid` int DEFAULT NULL,
  `customerid` int DEFAULT NULL,
  `storeid` int DEFAULT NULL,
  `staffid` int DEFAULT NULL,
  `saledate` date DEFAULT NULL,
  `quantity` int DEFAULT NULL,
  `price` decimal(10,2) DEFAULT NULL,
  `totalsales` decimal(10,2) DEFAULT NULL,
  PRIMARY KEY (`saleid`),
  KEY `productid` (`productid`),
  KEY `customerid` (`customerid`),
  KEY `storeid` (`storeid`),
  KEY `staffid` (`staffid`),
  KEY `saledate` (`saledate`),
  CONSTRAINT `fact_sales_ibfk_1` FOREIGN KEY (`productid`) REFERENCES `dim_product` (`productid`),
  CONSTRAINT `fact_sales_ibfk_2` FOREIGN KEY (`customerid`) REFERENCES `dim_customer` (`customerid`),
  CONSTRAINT `fact_sales_ibfk_3` FOREIGN KEY (`storeid`) REFERENCES `dim_store` (`storeid`),
  CONSTRAINT `fact_sales_ibfk_4` FOREIGN KEY (`staffid`) REFERENCES `dim_staff` (`staffid`),
  CONSTRAINT `fact_sales_ibfk_5` FOREIGN KEY (`saledate`) REFERENCES `dim_time` (`saledate`)
